SELECT p.id AS id, p.dept_sub_id AS deptSubId, p.worker_id AS workerId, p.date AS date, p.user_id AS userId, p.maximum AS maximum, p.description AS description, w.name AS workerName, ds.name AS deptSubName, d.name AS deptName, d.id AS deptId, gu.user_name AS userName FROM gas_worker_plan p LEFT JOIN gas_worker w ON p.worker_id = w.id LEFT JOIN medical_dept_sub ds ON p.dept_sub_id = ds.id LEFT JOIN medical_dept d ON ds.dept_id = d.id LEFT JOIN gas_user gu ON p.user_id = gu.id WHERE 1=1
AND p.date >= #{startDate}
AND p.date <= #{endDate}
AND p.dept_sub_id = #{deptSubId}
AND d.id = #{deptId}
ORDER BY p.date ASC, p.dept_sub_id ASC

SELECT p.id AS id, p.dept_sub_id AS deptSubId, p.worker_id AS workerId, p.date AS date, p.user_id AS userId, p.maximum AS maximum, p.description AS description, p.file_path AS filePath, w.name AS workerName, ds.name AS deptSubName, d.name AS deptName, d.id AS deptId, gu.user_name AS userName, (SELECT COUNT(*) FROM gas_worker_plan p2 WHERE p2.dept_sub_id = p.dept_sub_id AND p2.date = p.date) AS actualCount, (SELECT MAX(p3.maximum) FROM gas_worker_plan p3 WHERE p3.dept_sub_id = p.dept_sub_id AND p3.date = p.date) AS maxPeople FROM gas_worker_plan p LEFT JOIN gas_worker w ON p.worker_id = w.id LEFT JOIN medical_dept_sub ds ON p.dept_sub_id = ds.id LEFT JOIN medical_dept d ON ds.dept_id = d.id LEFT JOIN gas_user gu ON p.user_id = gu.id WHERE 1=1
AND w.name LIKE CONCAT("%", #{workerName}, "%")
AND d.id = #{deptId}
AND p.date >= #{startDate}
AND p.date <= #{endDate}
ORDER BY p.date DESC, p.id DESC LIMIT #{start}, #{length}

SELECT COUNT(*) FROM gas_worker_plan p LEFT JOIN gas_worker w ON p.worker_id = w.id LEFT JOIN medical_dept_sub ds ON p.dept_sub_id = ds.id LEFT JOIN medical_dept d ON ds.dept_id = d.id LEFT JOIN gas_user gu ON p.user_id = gu.id WHERE 1=1
AND w.name LIKE CONCAT("%", #{workerName}, "%")
AND d.id = #{deptId}
AND p.date >= #{startDate}
AND p.date <= #{endDate}

SELECT COUNT(*)
FROM gas_worker_plan
WHERE dept_sub_id = #{deptSubId}
AND date = #{date}

    AND id != #{excludeId}

SELECT MAX(maximum)
FROM gas_worker_plan
WHERE dept_sub_id = #{deptSubId}
AND date = #{date}

mapper.update:
UPDATE gas_worker_plan
SET file_path = #{filePath}
WHERE id = #{id}
